import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext"
import { useState } from "react";
import { isNotEmpty, isValidEmail } from "../utils/validations";

export default function Login() {
  const {user, logIn, sendOTP} = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');
  const [otp, setOtp] = useState('');
  const [error, setError] = useState('');

  if(user) {
    navigate('/view');
  }

  const handleSendOTP = (e) => {
    e.preventDefault();
    if(!isNotEmpty(email) || !isValidEmail(email)) {
      setError('Please enter a valid email address')
      return;
    }
    const success = sendOTP(email);
    if(success) {
      setStep(2);
      setError('');
    } else {
      setError('Failed to send OTP');
    }
  }

  const handleVerifyOTP = async (e) => {
    e.preventDefault();
    if(!isNotEmpty(otp)) {
      setError('Please enter OTP')
      return;
    }
    if(!isNotEmpty(password)) {
      setError('Please enter password')
      return;
    }
    const success = await logIn(email, otp, password);
    if(success) {
      navigate('/view')
    } else {
      setError('Invalid OTP or password.')
    }
  }

  return (
    <div className="panel login-panel">
      <h2>Login</h2>
      {step === 1 ? (
        <form onSubmit={handleSendOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="login-email">Email:</label>
            <input
              id="login-email"
              type="email"
              placeholder="Enter email address"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Send OTP
          </button>
          <p>
            <Link to="/signup">Sign up here</Link>
          </p>
          <p>
            <button type="button" onClick={() => setStep(3)} className="link-btn">Forgot Password?</button>
          </p>
        </form>
      ) : (
        <form onSubmit={handleVerifyOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="login-otp">OTP:</label>
            <input
              id="login-otp"
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="login-password">Password:</label>
            <input
              id="login-password"
              type="password"
              placeholder="Enter password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Verify OTP
          </button>
          <p>
            <button type="button" onClick={() => setStep(1)}>Back</button>
          </p>
        </form>
      )}
    </div>
  )
}
